mapper.select:
SELECT , pa.name AS area_name FROM bike b LEFT JOIN parking_area pa ON b.area_id = pa.id
AND b.bike_code LIKE CONCAT('%', #{bikeCode}, '%') AND b.status = #{status} AND b.area_id = #{areaId}
ORDER BY b.create_time DESC

mapper.update:
UPDATE bike
bike_code = #{bikeCode}, status = #{status}, lng = #{lng}, lat = #{lat}, area_id = #{areaId},
WHERE id = #{id}
